function _recordAudit(action, item, before, after) {
  _auditLog.push({
    id:          _auditLog.length + 1,
    timestamp:   new Date().toISOString(),
    created_at:  new Date().toISOString(),
    action,
    entity:      'item',
    entity_id:   item.id,
    entity_name: item.name,
    username:    'admin',
    before,
    after,
  });
}
